def prime1(givenNumber):
    primes = []
    for possiblePrime in range(2, givenNumber + 1):
        isPrime = 1
        for num in range(2, possiblePrime):
            if possiblePrime % num == 0:
                isPrime = 0
        if isPrime:
            primes.append(possiblePrime)
    return primes

